        ...(option.required ? { takes_value: 'required' } : {}),
        ...(option.optional ? { takes_value: 'optional' } : {}),
        ...(option.mandatory ? { required: true } : {}),
        ...(option.defaultValue !== undefined ? { default: option.defaultValue } : {}),
